// ffi.rs is the C-ABI boundary: these `extern "C"` entry points deref pointers
// supplied by the C/Swift caller, which owns their validity ‚Äî not us.
#![allow(clippy::not_unsafe_ptr_arg_deref)]

//! The stable C ABI the native UI links (committed `dontspeak.h`, generated by
//! cbindgen). The app is an informational menu-bar + health panel, so this
//! surface is small and HANDLE-FREE (no opaque handle type): read-only probes,
//! the in-process engine lifecycle (start/stop/reload), a few session controls
//! (mute, TTS provider, locale), shared UI constants/formatters/i18n lookups,
//! and the string free. The rich control surface
//! (voice/engine/language/rate/toggles/downloads) lives in DontSpeak.

use std::ffi::{CString, c_char};
use std::panic::{AssertUnwindSafe, catch_unwind};

use crate::{engine, models};

// ‚îÄ‚îÄ In-process engine host ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
// The lifecycle state lives in [`crate::host`] (the ONE owner, kept out of this boundary so
// a stray second start can't spawn a competing engine); these C entry points are thin
// adapters returning the u8 the committed `dontspeak.h` documents.

/// Start the engine on a background thread if not already running. Returns 1 if
/// it is now running (started or already up), 0 on failure.
#[unsafe(no_mangle)]
pub extern "C" fn ds_engine_start() -> u8 {
    guard_val(0, || crate::host::engine_start() as u8)
}

/// Stop the engine (clear the run flag, join the thread). Returns 1 if an engine
/// was running, 0 if none. Safe to call on quit.
#[unsafe(no_mangle)]
pub extern "C" fn ds_engine_stop() -> u8 {
    guard_val(0, || crate::host::engine_stop() as u8)
}

/// Ask the running engine to re-read its config (no restart). Returns 1 if an
/// engine is running, else 0.
#[unsafe(no_mangle)]
pub extern "C" fn ds_engine_reload() -> u8 {
    guard_val(0, || crate::host::engine_reload() as u8)
}

/// Set global MUTE (the tray "Mute" checkbox). `on != 0` mutes ‚Äî playback keeps draining,
/// only the audio is silenced. Sent to the running engine over IPC (the same channel the
/// status read uses); returns 1 if the request was delivered, 0 if the engine is down.
#[unsafe(no_mangle)]
pub extern "C" fn ds_set_muted(on: u8) -> u8 {
    guard_val(0, || {
        let Some(paths) = ds_config::Paths::resolve() else {
            return 0;
        };
        match ds_ipc::request(
            &paths.engine_sock,
            &ds_ipc::Request::SetMuted { on: on != 0 },
        ) {
            Ok(_) => 1,
            Err(_) => 0,
        }
    })
}

