/// Speech (Windows) / TODO (Linux). The cross-platform seam behind every UI's System-TTS
/// "Manage voices" affordance, so each platform launches the same per-OS page from one call.
/// Returns 1 if a page was launched, 0 if unsupported/failed. HANDLE-FREE ‚Äî no engine needed.
#[unsafe(no_mangle)]
pub extern "C" fn ds_open_voice_settings() -> u8 {
    guard_val(0, || ds_tts::system::open_voice_settings() as u8)
}

/// Run `f`, returning `default` on a panic (panics must never cross the FFI
/// boundary). All exported fns are read-only, so a default is always safe.
fn guard_val<T>(default: T, f: impl FnOnce() -> T) -> T {
    catch_unwind(AssertUnwindSafe(f)).unwrap_or(default)
}

/// Allocate a Rust string into a heap C string the caller frees with
/// `ds_string_free`. An interior NUL (impossible in our data) ‚Üí "".
fn to_cstring(s: impl Into<Vec<u8>>) -> *mut c_char {
    match CString::new(s) {
        Ok(c) => c.into_raw(),
        Err(_) => CString::new("").unwrap().into_raw(),
    }
}

/// Read an inbound C string into an owned String (empty if NULL or invalid UTF-8).
fn cstr_or_empty(p: *const c_char) -> String {
    cstr_or(p, "")
}

/// Read an inbound C string, substituting `default` for a NULL pointer OR invalid
/// UTF-8 (a VALID string ‚Äî including an empty one ‚Äî is returned as-is). The one
/// place the NULL/bad-UTF-8 fallback is decided; each caller passes its own
/// intended default explicitly.
fn cstr_or(p: *const c_char, default: &str) -> String {
    if p.is_null() {
        return default.to_string();
    }
    unsafe { std::ffi::CStr::from_ptr(p) }
        .to_str()
        .unwrap_or(default)
        .to_string()
}

