/// The engine's model-status JSON (presence + per-subsystem running map). Owned
/// `char*` the caller frees with `ds_string_free`; `"{}"` if the engine is
/// down. HANDLE-FREE ‚Äî safe off the main thread.
#[unsafe(no_mangle)]
pub extern "C" fn ds_model_status_json() -> *mut c_char {
    guard_val(to_cstring("{}"), || {
        let Some(paths) = ds_config::Paths::resolve() else {
            return to_cstring("{}");
        };
        match ds_ipc::request(&paths.engine_sock, &ds_ipc::Request::ModelStatus) {
            Ok(ds_ipc::Response::ModelStatus { status }) => to_cstring(status.to_string()),
            _ => to_cstring("{}"),
        }
    })
}

/// Like [`ds_model_status_json`] but BLOCKS until the engine's status sequence
/// differs from `since`, or `timeout_ms` elapses ‚Äî then returns the current status
/// JSON (whose `seq` field is the new sequence to pass as `since` next time). This is
/// the PUSH transport for the dictation overlay: the UI calls it on a DEDICATED
/// background thread (never the UI thread ‚Äî it blocks) in a loop, re-rendering the
/// instant a partial lands instead of polling on a timer. Pass `since = 0` first
/// (returns immediately with the current state). Owned `char*`, free with
/// `ds_string_free`; `"{}"` if the engine is down.
#[unsafe(no_mangle)]
pub extern "C" fn ds_model_status_wait(since: u64, timeout_ms: u32) -> *mut c_char {
    guard_val(to_cstring("{}"), || {
        let Some(paths) = ds_config::Paths::resolve() else {
            return to_cstring("{}");
        };
        match ds_ipc::request(
            &paths.engine_sock,
            &ds_ipc::Request::WaitModelStatus {
                since,
                timeout_ms: timeout_ms as u64,
            },
        ) {
            Ok(ds_ipc::Response::ModelStatus { status }) => to_cstring(status.to_string()),
            _ => to_cstring("{}"),
        }
    })
}

