// ‚îÄ‚îÄ Localization (shared ds-i18n catalog) ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
// Every platform UI renders ONE catalog through these: macOS (Swift) and Windows
// (WinUI) call them instead of hardcoding/duplicating literals. English is the
// fallback; the active locale defaults to the OS language (sys-locale), overridable.

/// Set the active UI locale (BCP-47 or a bare language tag, e.g. "de"). NULL is a no-op.
/// Unknown locales fall back to English at lookup. HANDLE-FREE ‚Äî no engine needed.
#[unsafe(no_mangle)]
pub extern "C" fn ds_set_locale(locale: *const c_char) {
    guard_val((), || {
        let loc = cstr_or_empty(locale);
        if !loc.is_empty() {
            ds_i18n::set_locale(&loc);
        }
    });
}

/// The active UI locale tag ‚Äî so a UI can match its native number formatter to the
/// catalog's language. Owned `char*`, free with `ds_string_free`. HANDLE-FREE.
#[unsafe(no_mangle)]
pub extern "C" fn ds_locale() -> *mut c_char {
    guard_val(to_cstring("en"), || to_cstring(ds_i18n::locale()))
}

/// Look up a localized UI string by `key` (a C string). English fallback; a missing key
