// ‚îÄ‚îÄ Shared status-panel formatters (one implementation, every UI) ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
// The small NON-numeric label assembly the status panels used to duplicate. Both the
// macOS SwiftUI app and the Windows WinUI app call these instead of reimplementing
// them. Culture-sensitive NUMBER formatting (RTF ranges, MB/GB, %) stays in each UI.

/// Localized hover word for an engine lifecycle state. `state` is the model-status token from
/// the canonical [`ds_status::EngineState`] vocabulary ("running"|"idle"|"warming"|
/// "downloading"|"failed"|"blocked"|"missing"),
/// `progress` the 0..1 download fraction (only used for "downloading"), `why` the
/// failure reason (only used for "failed"; empty ‚Üí the generic default). Owned `char*`,
/// free with `ds_string_free`. HANDLE-FREE.
#[unsafe(no_mangle)]
pub extern "C" fn ds_engine_state_word(
    state: *const c_char,
    progress: f64,
    why: *const c_char,
) -> *mut c_char {
    guard_val(to_cstring(""), || {
        to_cstring(crate::status_fmt::engine_state_word(
            &cstr_or_empty(state),
            progress,
            &cstr_or_empty(why),
        ))
    })
}

/// As [`ds_engine_state_word`], plus the in-flight download's `file_index`/`file_count`
/// so a multi-file model set reads "<index>/<count> ¬∑ Downloading <pct>%". `0`/`0` ‚Üí plain.
/// Owned `char*`, free with `ds_string_free`. HANDLE-FREE.
#[unsafe(no_mangle)]
pub extern "C" fn ds_engine_state_word_files(
    state: *const c_char,
    progress: f64,
    why: *const c_char,
    file_index: i64,
    file_count: i64,
) -> *mut c_char {
    guard_val(to_cstring(""), || {
        to_cstring(crate::status_fmt::engine_state_word_files(
            &cstr_or_empty(state),
            progress,
            &cstr_or_empty(why),
            file_index,
            file_count,
        ))
    })
}

