/// Set the TTS execution provider for this session: `which` is "ort_cpu" | "ort_cuda" |
/// "ort_coreml" | "ane" | "auto" (NULL/unknown ‚Üí "auto"). The engine restarts the warm Kokoro child on
/// the new provider and resets its TTS stats (only if the active provider actually
/// changed). Returns 1 if the request reached the engine, else 0. The new provider
/// + fresh stats then show up via `ds_model_status_json`.
#[unsafe(no_mangle)]
pub extern "C" fn ds_set_provider(which: *const c_char) -> u8 {
    guard_val(0, || {
        // NULL/invalid-UTF-8 ‚Üí "auto" (let the engine pick the provider).
        let which = cstr_or(which, "auto");
        let Some(paths) = ds_config::Paths::resolve() else {
            return 0;
        };
        match ds_ipc::request(&paths.engine_sock, &ds_ipc::Request::SetProvider { which }) {
            Ok(ds_ipc::Response::Done) => 1,
            _ => 0,
        }
    })
}

/// Free a `char*` returned by any ds_* function. NULL is a no-op.
#[unsafe(no_mangle)]
pub extern "C" fn ds_string_free(s: *mut c_char) {
    guard_val((), || {
        if !s.is_null() {
            unsafe { drop(CString::from_raw(s)) };
        }
    });
}
